INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (686, 173097, 7, 866, '异乡涂鸦（四）---屋外的爸爸', '下半学期终于在无聊寒假的落幕那刻和我招手，星期一的课程要上到晚上8点半。我拖着疲惫的身躯和朋友走进饭馆，“好饿呀。”我们两个一天都没有吃饭。人肚子饿的时候吃什么都觉得是美食。肚子填饱到一半的时候接到爸爸的电话“在哪里？我去接你。”“在吃饭呢，吃完再打电话给你。”
<br>
<br>与好友一个月没见，有许多说不完的话题，饭后也就没有给爸爸打电话，而是和好友一起走在回家的路上说着一个月里发生的事情。今天晚上的风特别冻，冰冷而又疲惫的身躯在欢笑声中得到一些温暖。在路口和朋友告别，电话又响起“我在路上就要到家了。”
<br>
<br>一个人飞快地走在回家的路上，不远处看见了爸爸的身影，模糊中那是穿着睡袍的爸爸。爸爸的头上仿佛有一团烟圈，我知道那是爸爸抽烟而造成的景象，或许还夹带着冰冷的雾气。我们全家都希望爸爸能戒烟，他却一直不肯。或许是抽了几十年的缘故吧！或许是因为爸爸是生意人吧！或者是说一个男人为了给予家人良好的生活环境绞尽脑汁，他需要一点寄托。烟就是爸爸的工作伙伴。为了让子女有更好的学习环境，更好的前途，爸爸想方设法投资移民来了墨尔本，爸爸语言不通却也能在一个陌生的城市做生意。这是我最佩服爸爸的地方，爸爸在我眼里也是一个成功的生意人，他有精明的头脑，我却怎么没有遗传到。我并没有因为爸爸抽烟而认同一个真正的男人就应该学会抽烟，反之我对烟极为反感，因为它时时刻刻在伤害爸爸的健康。以自己的身体健康去换取一点安慰，一点寄托，值得吗？我不懂，不明白抽了那支烟之后人就会舒服多了吗？
<br>
<br>看着屋外等待着女儿的爸爸，我想起了朱自清的《背影》，也回忆起童年。爸爸在我的影像中只有极小部分的记忆。因为他长年在外工作的缘故，童年里很少有和爸爸见面的机会。记得小时候妈妈曾经问我比较喜欢爸爸还是妈妈？我想了好久，我回答都喜欢。虽然爸爸经常不在身边，我还是相信爸爸是疼爱女儿的，他每次回来总是带给我最喜欢的芭比娃娃，他总爱掐我红红的小脸夹，虽然爸爸只是轻轻地一捏，我却感到无比的疼痛，爸爸的力气好大哦！但是我知道那是爸爸在疼爱女儿的方式，他或许并不知道他小小一捏却可以让我掉下眼泪，可是我心里仍然很开心。爸爸总爱亲我的小脸蛋，可是他的胡渣会搔痒我的脸，我便开始格格地笑。有次妈妈问我想念爸爸吗？我摸摸小脑袋，恩，想念。然后不过一会，爸爸就从楼梯走了上来对我笑。我好开心，爸爸又回来了。
<br>
<br>长大了，我渐渐不再是个会对爸爸撒娇的小女儿，甚至我和爸爸还常常起冲突。我的家庭，大家都可以像朋友一样，言论自由。人家说像我这种年纪容易和家庭产生矛盾，每次和爸爸大小声后，我总会后悔，因为我知道爸爸是疼爱我们的，只是他用他自己的方式，或许有时是我们接受不来的。
<br>
<br>这么冷的冬季夜晚，我一步步走在归途，看着离我越来越近的爸爸，突然心里一酸，有想哭的冲动。直到看着我平安到家，爸爸的表情似乎卸下了一块重担，屋外的爸爸终于尾随着我走进温暖的小屋。爸爸，以后不要等我了，女儿知道回家的路，也懂得照顾自己，爱惜自己了。', '下半学期终于在无聊寒假的落幕那刻和我招手，星期一的课程要上到晚上8点半。我拖着疲惫的身躯和朋友走进饭馆，“好饿呀。”我们两个一天都没有吃饭。人肚子饿的时候吃什么都觉得是美食。肚子填饱到一半的时候接到爸爸的电话“在哪里？我去接你。”“在吃饭呢，吃完再打电话给你。”

与好友一个月没见，有许多说不完的话题，饭后也就没有给爸爸打电话，而是和好友一起走在回家的路上说着一个月里发生的事情。今天晚上的风特别冻，冰冷而又疲惫的身躯在欢笑声中得到一些温暖。在路口和朋友告别，电话又响起“我在路上就要到家了。”

一个人飞快地走在回家的路上，不远处看见了爸爸的身影，模糊中那是穿着睡袍的爸爸。爸爸的头上仿佛有一团烟圈，我知道那是爸爸抽烟而造成的景象，或许还夹带着冰冷的雾气。我们全家都希望爸爸能戒烟，他却一直不肯。或许是抽了几十年的缘故吧！或许是因为爸爸是生意人吧！或者是说一个男人为了给予家人良好的生活环境绞尽脑汁，他需要一点寄托。烟就是爸爸的工作伙伴。为了让子女有更好的学习环境，更好的前途，爸爸想方设法投资移民来了墨尔本，爸爸语言不通却也能在一个陌生的城市做生意。这是我最佩服爸爸的地方，爸爸在我眼里也是一个成功的生意人，他有精明的头脑，我却怎么没有遗传到。我并没有因为爸爸抽烟而认同一个真正的男人就应该学会抽烟，反之我对烟极为反感，因为它时时刻刻在伤害爸爸的健康。以自己的身体健康去换取一点安慰，一点寄托，值得吗？我不懂，不明白抽了那支烟之后人就会舒服多了吗？

看着屋外等待着女儿的爸爸，我想起了朱自清的《背影》，也回忆起童年。爸爸在我的影像中只有极小部分的记忆。因为他长年在外工作的缘故，童年里很少有和爸爸见面的机会。记得小时候妈妈曾经问我比较喜欢爸爸还是妈妈？我想了好久，我回答都喜欢。虽然爸爸经常不在身边，我还是相信爸爸是疼爱女儿的，他每次回来总是带给我最喜欢的芭比娃娃，他总爱掐我红红的小脸夹，虽然爸爸只是轻轻地一捏，我却感到无比的疼痛，爸爸的力气好大哦！但是我知道那是爸爸在疼爱女儿的方式，他或许并不知道他小小一捏却可以让我掉下眼泪，可是我心里仍然很开心。爸爸总爱亲我的小脸蛋，可是他的胡渣会搔痒我的脸，我便开始格格地笑。有次妈妈问我想念爸爸吗？我摸摸小脑袋，恩，想念。然后不过一会，爸爸就从楼梯走了上来对我笑。我好开心，爸爸又回来了。

长大了，我渐渐不再是个会对爸爸撒娇的小女儿，甚至我和爸爸还常常起冲突。我的家庭，大家都可以像朋友一样，言论自由。人家说像我这种年纪容易和家庭产生矛盾，每次和爸爸大小声后，我总会后悔，因为我知道爸爸是疼爱我们的，只是他用他自己的方式，或许有时是我们接受不来的。

这么冷的冬季夜晚，我一步步走在归途，看着离我越来越近的爸爸，突然心里一酸，有想哭的冲动。直到看着我平安到家，爸爸的表情似乎卸下了一块重担，屋外的爸爸终于尾随着我走进温暖的小屋。爸爸，以后不要等我了，女儿知道回家的路，也懂得照顾自己，爱惜自己了。', '有人说：“幸福是短暂的，它有翅膀，随时都会飞离你的视线。”

却也有人说：“幸福的翅膀有个美丽的名字称之为幸福之羽翼~~人类都想把周围的事物美化，而得到更美好的。当他们为幸福画上了翅膀，以为这样会让它像天使的羽翼一样美丽，却还没有发觉到原来幸福是自己放走的。而幸福之羽翼就是自己的双手。”', '2002-07-22 23:12:00', 5, '20020818161310_bbsid_173097_board_7_d704be5b5c.html', '20020818161310');
